function addSequencerL2Batch(
    uint256 sequenceNumber,
    bytes calldata data,
    uint256 afterDelayedMessagesRead,
    IGasRefunder gasRefunder,
    uint256 prevMessageCount,
    uint256 newMessageCount
) external override refundsGas(gasRefunder, IReader4844(address(0))) {
    if (!isBatchPoster[msg.sender] && msg.sender != address(rollup)) revert NotBatchPoster();
    if (isDelayProofRequired(afterDelayedMessagesRead)) revert DelayProofRequired();

    addSequencerL2BatchFromCalldataImpl(
        sequenceNumber, data, afterDelayedMessagesRead,
        prevMessageCount, newMessageCount, false  // isFromOrigin = false
    );
}
